package builder

import (
	"context"

	"google.golang.org/grpc"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/plugin/builder"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/plugin/buildpack"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type BuilderProxy struct {
	builder.UnimplementedBuilderServer
	client builder.BuilderClient
}

func init() {
	proxyutil.Register(&builder.Builder_ServiceDesc, NewBuilderProxy)
}
func NewBuilderProxy(cc grpc.ClientConnInterface) builder.BuilderServer {
	return &BuilderProxy{client: builder.NewBuilderClient(cc)}
}
func (p *BuilderProxy) Build(ctx context.Context, in *buildpack.CompileParams) (*builder.BuildResponse, error) {
	return proxyutil.ProxyMethod[buildpack.CompileParams, builder.BuildResponse](p.client.Build)(ctx, in)
}
